using System.Windows.Forms;

public class MainForm : Form
{
    private StatusStrip statusStrip;
    private ToolStripStatusLabel statusLabel;

    public MainForm()
    {
        statusStrip = new StatusStrip();
        statusLabel = new ToolStripStatusLabel("Ready");

        // .NET 9 breaking change: the default ToolStrip/StatusStrip render mode
        // changed from Professional to System. Explicitly set Professional to
        // preserve the .NET 8 visual appearance.
        statusStrip.RenderMode = ToolStripRenderMode.Professional;

        statusStrip.Items.Add(statusLabel);
        Controls.Add(statusStrip);
    }
}

using System;
using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyTypeEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext context)
        => UITypeEditorEditStyle.DropDown;

    public override object EditValue(
        ITypeDescriptorContext context,
        IServiceProvider provider,
        object value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;

        if (editorService == null)
            return value;

        var control = CreateDropDownControl(value);

        // .NET 9 breaking change: DropDownControl now throws
        // ArgumentNullException when passed null. Guard against it.
        if (control != null)
        {
            editorService.DropDownControl(control);
            value = ((ListBox)control).SelectedItem ?? value;
        }

        return value;
    }

    private Control CreateDropDownControl(object currentValue)
    {
        // Return null when there are no items to display; callers now
        // check for null before passing to DropDownControl.
        var items = GetAvailableItems();
        if (items == null || items.Length == 0)
            return null;

        var listBox = new ListBox();
        listBox.Items.AddRange(items);
        listBox.SelectedItem = currentValue;
        return listBox;
    }

    private string[] GetAvailableItems()
    {
        return new[] { "Option A", "Option B", "Option C" };
    }
}

